  1→export type OpenRouterReasoningEffort = "xhigh" | "high" | "medium" | "low" | "minimal" | "none";
  2→
  3→export type OpenRouterReasoningOptions = {
  4→  enabled?: boolean;
  5→  exclude?: boolean;
  6→  max_tokens?: number;
  7→  effort?: OpenRouterReasoningEffort;
  8→};
  9→
 10→export type InferenceProvider = "openrouter" | "ollama";
 11→
 12→export type ServerConfig = {
 13→  inferenceProvider: InferenceProvider;
 14→  openRouterApiKey?: string;
 15→  ollamaBaseUrl?: string;
 16→  chatAgentModelId: string;
 17→  extractionModelId: string;
 18→  pmAgentModelId: string;
 19→  analyticsAgentModelId: string;
 20→  embeddingModelId: string;
 21→  embeddingDimension: number;
 22→  extractionStoreThreshold: number;
 23→  extractionDisplayThreshold: number;
 24→  openRouterReasoning?: OpenRouterReasoningOptions;
 25→  surrealUrl: string;
 26→  surrealUsername: string;
 27→  surrealPassword: string;
 28→  surrealNamespace: string;
 29→  surrealDatabase: string;
 30→  port: number;
 31→  observerModelId: string;
 32→  scorerModelId: string;
 33→  githubWebhookSecret?: string;
 34→  betterAuthSecret: string;
 35→  betterAuthUrl: string;
 36→  githubClientId: string;
 37→  githubClientSecret: string;
 38→  anthropicApiUrl: string;
 39→  anthropicApiKey?: string;
 40→};
 41→
 42→export function loadServerConfig(): ServerConfig {
 43→  const inferenceProvider = parseInferenceProvider();
 44→
 45→  const openRouterApiKey = inferenceProvider === "openrouter"
 46→    ? requireEnv("OPENROUTER_API_KEY")
 47→    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;
 48→
 49→  const ollamaBaseUrl = inferenceProvider === "ollama"
 50→    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
 51→    : undefined;
 52→
 53→  const extractionStoreThreshold = parseUnitInterval(
 54→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 55→    "EXTRACTION_STORE_THRESHOLD",
 56→  );
 57→
 58→  const extractionDisplayThreshold = parseUnitInterval(
 59→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 60→    "EXTRACTION_DISPLAY_THRESHOLD",
 61→  );
 62→
 63→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 64→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 65→  }
 66→
 67→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 68→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 69→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
 70→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 71→  const embeddingModelId = requireEnv("EMBEDDING_MODEL");
 72→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 73→
 74→  const surrealUrl = requireEnv("SURREAL_URL");
 75→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 76→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 77→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 78→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 79→
 80→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 81→  const observerModelId = optionalEnv("OBSERVER_MODEL") ?? extractionModelId;
 82→  const scorerModelId = optionalEnv("SCORER_MODEL") ?? extractionModelId;
 83→  const githubWebhookSecret = optionalEnv("GITHUB_WEBHOOK_SECRET");
 84→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 85→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 86→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 87→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 88→  const anthropicApiUrl = optionalEnv("ANTHROPIC_API_URL") ?? "https://api.anthropic.com";
 89→  const anthropicApiKey = optionalEnv("ANTHROPIC_API_KEY");
 90→
 91→  const openRouterReasoning = inferenceProvider === "openrouter"
 92→    ? parseOpenRouterReasoning()
 93→    : undefined;
 94→
 95→  return {
 96→    inferenceProvider,
 97→    ...(openRouterApiKey ? { openRouterApiKey } : {}),
 98→    ...(ollamaBaseUrl ? { ollamaBaseUrl } : {}),
 99→    chatAgentModelId,
100→    extractionModelId,
101→    pmAgentModelId,
102→    analyticsAgentModelId,
103→    embeddingModelId,
104→    embeddingDimension,
105→    extractionStoreThreshold,
106→    extractionDisplayThreshold,
107→    ...(openRouterReasoning ? { openRouterReasoning } : {}),
108→    surrealUrl,
109→    surrealUsername,
110→    surrealPassword,
111→    surrealNamespace,
112→    surrealDatabase,
113→    port,
114→    observerModelId,
115→    scorerModelId,
116→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
117→    betterAuthSecret,
118→    betterAuthUrl,
119→    githubClientId,
120→    githubClientSecret,
121→    anthropicApiUrl,
122→    ...(anthropicApiKey ? { anthropicApiKey } : {}),
123→  };
124→}
125→
126→function optionalEnv(name: string): string | undefined {
127→  const value = Bun.env[name]?.trim();
128→  if (!value || value.length === 0) return undefined;
129→  return value;
130→}
131→
132→function requireEnv(name: string): string {
133→  const value = Bun.env[name];
134→  if (!value || value.trim().length === 0) {
135→    throw new Error(`${name} is required`);
136→  }
137→
138→  return value;
139→}
140→
141→function parsePositiveInteger(value: string, envName: string): number {
142→  const parsed = Number(value);
143→  if (!Number.isInteger(parsed) || parsed < 1) {
144→    throw new Error(`${envName} must be a positive integer`);
145→  }
146→  return parsed;
147→}
148→
149→function parseUnitInterval(value: string, envName: string): number {
150→  const parsed = Number(value);
151→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
152→    throw new Error(`${envName} must be a number between 0 and 1`);
153→  }
154→
155→  return parsed;
156→}
157→
158→function parseInferenceProvider(): InferenceProvider {
159→  const value = Bun.env.INFERENCE_PROVIDER?.trim().toLowerCase();
160→  if (!value || value === "openrouter") return "openrouter";
161→  if (value === "ollama") return "ollama";
162→  throw new Error("INFERENCE_PROVIDER must be one of: openrouter, ollama");
163→}
164→
165→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
166→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
167→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
168→
169→  if (!effortValue && !maxTokensValue) {
170→    return undefined;
171→  }
172→
173→  const reasoning: OpenRouterReasoningOptions = {};
174→
175→  if (effortValue) {
176→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
177→
178→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
179→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
180→    }
181→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
182→  }
183→
184→  if (maxTokensValue) {
185→    const parsed = Number(maxTokensValue);
186→    if (!Number.isFinite(parsed) || parsed < 1) {
187→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
188→    }
189→    reasoning.max_tokens = parsed;
190→  }
191→
192→  return reasoning;
193→}
