  1→import { createAdapterFactory, type CleanedWhere } from "better-auth/adapters";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→
  4→/**
  5→ * Custom SurrealDB v2 adapter for better-auth.
  6→ *
  7→ * Uses the project's existing Surreal connection (SDK v2) instead of creating
  8→ * its own. Field names arrive pre-mapped by the factory for configured core
  9→ * models (user/person, session, account, verification). Plugin models (OAuth
 10→ * tables) use better-auth's default camelCase naming which matches the DB schema.
 11→ *
 12→ * `findOne` returns `null` (not `undefined`) per better-auth contract —
 13→ * boundary exception to project no-null rule.
 14→ */
 15→export function surrealdbAdapter(surreal: Surreal) {
 16→  return createAdapterFactory({
 17→    config: {
 18→      adapterId: "surrealdb-v2",
 19→      adapterName: "SurrealDB v2",
 20→      usePlural: false,
 21→      supportsJSON: true,
 22→      supportsDates: true,
 23→      supportsBooleans: true,
 24→      supportsNumericIds: false,
 25→    },
 26→    adapter: ({ schema, getModelName, getFieldName }) => {
 27→      // Build FK map: { dbTableName → { dbColumnName → referencedDbTableName } }
 28→      const fkMap = new Map<string, Map<string, string>>();
 29→      for (const [defaultModel, modelDef] of Object.entries(schema)) {
 30→        const dbTable = getModelName(defaultModel);
 31→        const tableFks = new Map<string, string>();
 32→        for (const [defaultField, fieldAttr] of Object.entries(modelDef.fields)) {
 33→          if (fieldAttr.references?.field === "id") {
 34→            const dbColumn = getFieldName({ model: defaultModel, field: defaultField });
 35→            const refDbTable = getModelName(fieldAttr.references.model);
 36→            tableFks.set(dbColumn, refDbTable);
 37→          }
 38→        }
 39→        if (tableFks.size > 0) {
 40→          fkMap.set(dbTable, tableFks);
 41→        }
 42→      }
 43→
 44→      function getFkTable(table: string, field: string): string | undefined {
 45→        return fkMap.get(table)?.get(field);
 46→      }
 47→
 48→      /** Convert string FK values to RecordId for writes/where clauses. */
 49→      function toRecordId(table: string, field: string, value: unknown): unknown {
 50→        if (value === null || value === undefined) return value;
 51→        if (field === "id") return new RecordId(table, value as string);
 52→        const refTable = getFkTable(table, field);
 53→        if (refTable && typeof value === "string") return new RecordId(refTable, value);
 54→        return value;
 55→      }
 56→
 57→      /** Convert RecordId objects back to plain strings and SurrealDB Datetime to native Date for the factory. */
 58→      function fromRecord(value: unknown): unknown {
 59→        if (value instanceof RecordId) return value.id as string;
 60→        // SurrealDB SDK returns Datetime objects (not native Date) for datetime fields.
 61→        // better-auth expects native Date instances (e.g. JWT adapter calls .getTime()).
 62→        if (
 63→          value !== null &&
 64→          typeof value === "object" &&
 65→          !(value instanceof Date) &&
 66→          typeof (value as any).toISOString === "function"
 67→        ) {
 68→          return new Date((value as any).toISOString());
 69→        }
 70→        return value;
 71→      }
 72→
 73→      function transformOutputRecord(record: Record<string, unknown>): Record<string, unknown> {
 74→        const out: Record<string, unknown> = {};
 75→        for (const [key, value] of Object.entries(record)) {
 76→          out[key] = fromRecord(value);
 77→        }
 78→        return out;
 79→      }
 80→
 81→      /** Prepare content for CREATE/UPDATE — convert FK strings to RecordId, strip `id`, omit nulls. */
 82→      function transformInputRecord(
 83→        data: Record<string, unknown>,
 84→        table: string,
 85→        stripId: boolean,
 86→      ): Record<string, unknown> {
 87→        const content: Record<string, unknown> = {};
 88→        for (const [key, value] of Object.entries(data)) {
 89→          if (stripId && key === "id") continue;
 90→          if (value === null || value === undefined) continue; // SurrealDB option<T> uses NONE (omit)
 91→          content[key] = toRecordId(table, key, value);
 92→        }
 93→        return content;
 94→      }
 95→
 96→      /** Build parameterized WHERE clause from CleanedWhere[]. */
 97→      function buildWhere(
 98→        where: CleanedWhere[],
 99→        table: string,
100→      ): { clause: string; params: Record<string, unknown> } {
101→        const parts: string[] = [];
102→        const params: Record<string, unknown> = {};
103→
104→        for (let i = 0; i < where.length; i++) {
105→          const w = where[i];
106→          const paramKey = `w${i}`;
107→          const value = toRecordId(table, w.field, w.value);
108→          params[paramKey] = value;
109→
110→          const connector = i > 0 ? ` ${w.connector} ` : "";
111→          let expr: string;
112→
113→          switch (w.operator) {
114→            case "eq":
115→              if (value === null) {
116→                expr = `${w.field} IS NONE`;
117→                delete params[paramKey];
118→              } else {
119→                expr = `${w.field} = $${paramKey}`;
120→              }
121→              break;
122→            case "ne":
123→              if (value === null) {
124→                expr = `${w.field} IS NOT NONE`;
125→                delete params[paramKey];
126→              } else {
127→                expr = `${w.field} != $${paramKey}`;
128→              }
129→              break;
130→            case "gt":
131→              expr = `${w.field} > $${paramKey}`;
132→              break;
133→            case "gte":
134→              expr = `${w.field} >= $${paramKey}`;
135→              break;
136→            case "lt":
137→              expr = `${w.field} < $${paramKey}`;
138→              break;
139→            case "lte":
140→              expr = `${w.field} <= $${paramKey}`;
141→              break;
142→            case "in":
143→              expr = `${w.field} IN $${paramKey}`;
144→              break;
145→            case "not_in":
146→              expr = `${w.field} NOT IN $${paramKey}`;
147→              break;
148→            case "contains":
149→              expr = `${w.field} CONTAINS $${paramKey}`;
150→              break;
151→            case "starts_with":
152→              expr = `string::starts_with(${w.field}, $${paramKey})`;
153→              break;
154→            case "ends_with":
155→              expr = `string::ends_with(${w.field}, $${paramKey})`;
156→              break;
157→            default:
158→              expr = `${w.field} = $${paramKey}`;
159→          }
160→
161→          parts.push(`${connector}${expr}`);
162→        }
163→
164→        return { clause: parts.join(""), params };
165→      }
166→
167→      return {
168→        create: async ({ model, data }) => {
169→          const table = getModelName(model);
170→          const id = data.id as string;
171→          const record = new RecordId(table, id);
172→          const content = transformInputRecord(data, table, true);
173→
174→          const [result] = await surreal.query<[Record<string, unknown>[]]>(
175→            `CREATE $record CONTENT $content RETURN AFTER;`,
176→            { record, content },
177→          );
178→
179→          if (!result?.[0]) throw new Error(`Failed to create ${table} record`);
180→          return transformOutputRecord(result[0]) as any;
181→        },
182→
183→        findOne: async ({ model, where }) => {
184→          const table = getModelName(model);
185→          const { clause, params } = buildWhere(where, table);
186→
187→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
188→            `SELECT * FROM ${table} WHERE ${clause} LIMIT 1;`,
189→            params,
190→          );
191→
192→          const row = results?.[0];
193→          if (!row) return null; // better-auth contract: null, not undefined
194→          return transformOutputRecord(row) as any;
195→        },
196→
197→        findMany: async ({ model, where, limit, sortBy, offset }) => {
198→          const table = getModelName(model);
199→          let query = `SELECT * FROM ${table}`;
200→          let params: Record<string, unknown> = {};
201→
202→          if (where && where.length > 0) {
203→            const w = buildWhere(where, table);
204→            query += ` WHERE ${w.clause}`;
205→            params = w.params;
206→          }
207→          if (sortBy) {
208→            query += ` ORDER BY ${sortBy.field} ${sortBy.direction.toUpperCase()}`;
209→          }
210→          if (limit !== undefined) {
211→            query += ` LIMIT ${Number(limit)}`;
212→          }
213→          if (offset !== undefined) {
214→            query += ` START ${Number(offset)}`;
215→          }
216→
217→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
218→            `${query};`,
219→            params,
220→          );
221→
222→          return (results ?? []).map((r) => transformOutputRecord(r)) as any[];
223→        },
224→
225→        update: async ({ model, where, update: updateData }) => {
226→          const table = getModelName(model);
227→          const { clause, params } = buildWhere(where, table);
228→          const content = transformInputRecord(updateData as Record<string, unknown>, table, true);
229→
230→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
231→            `UPDATE ${table} MERGE $content WHERE ${clause} RETURN AFTER;`,
232→            { ...params, content },
233→          );
234→
235→          const row = results?.[0];
236→          if (!row) return null;
237→          return transformOutputRecord(row) as any;
238→        },
239→
240→        updateMany: async ({ model, where, update: updateData }) => {
241→          const table = getModelName(model);
242→          const { clause, params } = buildWhere(where, table);
243→          const content = transformInputRecord(updateData as Record<string, unknown>, table, true);
244→
245→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
246→            `UPDATE ${table} MERGE $content WHERE ${clause};`,
247→            { ...params, content },
248→          );
249→
250→          return results?.length ?? 0;
251→        },
252→
253→        delete: async ({ model, where }) => {
254→          const table = getModelName(model);
255→          const { clause, params } = buildWhere(where, table);
256→          await surreal.query(`DELETE FROM ${table} WHERE ${clause};`, params);
257→        },
258→
259→        deleteMany: async ({ model, where }) => {
260→          const table = getModelName(model);
261→          const { clause, params } = buildWhere(where, table);
262→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
263→            `DELETE FROM ${table} WHERE ${clause} RETURN BEFORE;`,
264→            params,
265→          );
266→          return results?.length ?? 0;
267→        },
268→
269→        count: async ({ model, where }) => {
270→          const table = getModelName(model);
271→          let query: string;
272→          let params: Record<string, unknown> = {};
273→
274→          if (where && where.length > 0) {
275→            const w = buildWhere(where, table);
276→            query = `SELECT count() FROM ${table} WHERE ${w.clause} GROUP ALL;`;
277→            params = w.params;
278→          } else {
279→            query = `SELECT count() FROM ${table} GROUP ALL;`;
280→          }
281→
282→          const [results] = await surreal.query<[Array<{ count: number }>]>(query, params);
283→          return results?.[0]?.count ?? 0;
284→        },
285→      };
286→    },
287→  });
288→}
