208→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
209→  const startedAt = performance.now();
210→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
211→
212→  try {
213→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
214→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
215→    if (!workspace) {
216→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
217→    }
218→
219→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
220→    const conversationId = conversationRecord.id as string;
221→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
222→
223→    const messages = rawMessages.map((row) => ({
224→      id: row.id,
225→      role: row.role,
226→      text: row.text,
227→      createdAt: toIsoString(row.createdAt),
228→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
229→      ...(row.inherited ? { inherited: true } : {}),
230→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
231→    } satisfies WorkspaceBootstrapMessage));
232→
233→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
234→    const onboardingState = toOnboardingState(workspace);
235→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
236→
237→    const payload: WorkspaceBootstrapResponse = {
238→      workspaceId: workspace.id.id as string,
239→      workspaceName: workspace.name,
240→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
241→      ...(workspace.repo_path ? { repoPath: workspace.repo_path } : {}),
242→      onboardingComplete: workspace.onboarding_complete,
243→      onboardingState,
244→      conversationId: conversationRecord.id as string,
245→      messages,
246→      seeds,
247→      sidebar,
248→    };
249→
250→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
251→      workspaceId,
252→      conversationId: conversationRecord.id as string,
253→      messageCount: messages.length,
254→      seedCount: seeds.length,
255→      durationMs: elapsedMs(startedAt),
256→    });
257→
258→    return jsonResponse(payload, 200);
259→  } catch (error) {
260→    if (error instanceof HttpError) {
261→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
262→        workspaceId,
263→        statusCode: error.status,
264→      });
265→      return jsonError(error.message, error.status);
266→    }
267→
268→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
269→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
270→    return jsonError(errorText, 500);
271→  }
272→}
