428→async function handleWorkspaceConversation(
429→  deps: ServerDependencies,
430→  workspaceId: string,
431→  conversationId: string,
432→): Promise<Response> {
433→  const startedAt = performance.now();
434→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
435→    workspaceId,
436→    conversationId,
437→  });
438→
439→  try {
440→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
441→    const conversationRecord = new RecordId("conversation", conversationId);
442→    const conversation = await deps.surreal.select<{
443→      id: RecordId<"conversation", string>;
444→      workspace: RecordId<"workspace", string>;
445→      discusses?: RecordId;
446→    }>(conversationRecord);
447→
448→    if (!conversation) {
449→      throw new HttpError(404, `conversation not found: ${conversationId}`);
450→    }
451→
452→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
453→      throw new HttpError(400, "conversation does not belong to workspace");
454→    }
455→
456→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
457→
458→    const messages = rawMessages.map((row) => ({
459→      id: row.id,
460→      role: row.role,
461→      text: row.text,
462→      createdAt: toIsoString(row.createdAt),
463→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
464→      ...(row.inherited ? { inherited: true } : {}),
465→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
466→    } satisfies WorkspaceBootstrapMessage));
467→
468→    let discussEntity: DiscussEntitySummary | undefined;
469→    if (conversation.discusses) {
470→      const entityRecord = conversation.discusses as GraphEntityRecord;
471→      const name = await readEntityName(deps.surreal, entityRecord);
472→      if (name) {
473→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
474→        discussEntity = {
475→          id: `${entityRecord.table.name}:${entityRecord.id as string}`,
476→          kind: entityRecord.table.name as EntityKind,
477→          name,
478→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
479→        };
480→      }
481→    }
482→
483→    const payload: WorkspaceConversationResponse = {
484→      conversationId,
485→      messages,
486→      ...(discussEntity ? { discussEntity } : {}),
487→    };
488→
489→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
490→      workspaceId,
491→      conversationId,
492→      messageCount: messages.length,
493→      durationMs: elapsedMs(startedAt),
494→    });
495→
496→    return jsonResponse(payload, 200);
497→  } catch (error) {
498→    if (error instanceof HttpError) {
499→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
500→        workspaceId,
501→        conversationId,
502→        statusCode: error.status,
503→      });
504→      return jsonError(error.message, error.status);
505→    }
506→
507→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
508→      workspaceId,
509→      conversationId,
510→    });
511→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
512→    return jsonError(errorText, 500);
513→  }
514→}
