520→async function handleUpdateRepoPath(
521→  deps: ServerDependencies,
522→  workspaceId: string,
523→  request: Request,
524→  shellExec?: ShellExec,
525→): Promise<Response> {
526→  const startedAt = performance.now();
527→  logInfo("workspace.repo_path.update.started", "Repo path update started", { workspaceId });
528→
529→  try {
530→    let body: unknown;
531→    try {
532→      body = await request.json();
533→    } catch {
534→      return jsonError("Request body must be valid JSON", 400);
535→    }
536→
537→    if (!body || typeof body !== "object") {
538→      return jsonError("Body must be an object", 400);
539→    }
540→
541→    const { path: rawPath } = body as { path?: string };
542→    if (!rawPath || typeof rawPath !== "string" || rawPath.trim().length === 0) {
543→      return jsonError("path is required", 400);
544→    }
545→
546→    if (!shellExec) {
547→      return jsonError("shell execution not available", 500);
548→    }
549→
550→    const trimmedPath = rawPath.trim();
551→
552→    const repoValidation = await validateRepoPath(trimmedPath, shellExec);
553→    if (!repoValidation.ok) {
554→      return jsonError(repoValidation.error, 400);
555→    }
556→
557→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
558→
559→    await deps.surreal.query(
560→      "UPDATE $workspace SET repo_path = $repoPath, updated_at = time::now();",
561→      { workspace: workspaceRecord, repoPath: trimmedPath },
562→    );
563→
564→    logInfo("workspace.repo_path.update.completed", "Repo path update completed", {
565→      workspaceId,
566→      repoPath: trimmedPath,
567→      durationMs: elapsedMs(startedAt),
568→    });
569→
570→    return jsonResponse({ ok: true }, 200);
571→  } catch (error) {
572→    if (error instanceof HttpError) {
573→      logWarn("workspace.repo_path.update.http_error", "Repo path update failed with client-facing error", {
574→        workspaceId,
575→        statusCode: error.status,
576→      });
577→      return jsonError(error.message, error.status);
578→    }
579→
580→    logError("workspace.repo_path.update.failed", "Repo path update failed", error, { workspaceId });
581→    const errorText = error instanceof Error ? error.message : "repo path update failed";
582→    return jsonError(errorText, 500);
583→  }
584→}
