  1→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  2→import { createOllama } from "ollama-ai-provider";
  3→import { wrapLanguageModel } from "ai";
  4→import { devToolsMiddleware } from "@ai-sdk/devtools";
  5→import { Surreal } from "surrealdb";
  6→import type { ServerConfig } from "./config";
  7→import { createAuth, type Auth } from "../auth/config";
  8→import { bootstrapSigningKeyFromSurreal, type AsSigningKey } from "../oauth/as-key-management";
  9→
 10→const devtools = process.env.AI_DEVTOOLS === "1" ? devToolsMiddleware() : undefined;
 11→
 12→export async function createRuntimeDependencies(config: ServerConfig): Promise<{
 13→  surreal: Surreal;
 14→  analyticsSurreal: Surreal;
 15→  auth: Auth;
 16→  chatAgentModel: any;
 17→  extractionModel: any;
 18→  pmAgentModel: any;
 19→  analyticsAgentModel: any;
 20→  embeddingModel: any;
 21→  observerModel: any;
 22→  scorerModel: any;
 23→  asSigningKey: AsSigningKey;
 24→}> {
 25→  const surreal = new Surreal();
 26→  await surreal.connect(config.surrealUrl);
 27→  await surreal.signin({ username: config.surrealUsername, password: config.surrealPassword });
 28→  await surreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
 29→
 30→  const analyticsSurreal = new Surreal();
 31→  await analyticsSurreal.connect(config.surrealUrl);
 32→  await analyticsSurreal.signin({
 33→    namespace: config.surrealNamespace,
 34→    database: config.surrealDatabase,
 35→    username: "analytics",
 36→    password: "brain-analytics-readonly",
 37→  });
 38→  await analyticsSurreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
 39→
 40→  const wrap = (model: any) => devtools ? wrapLanguageModel({ model, middleware: devtools }) : model;
 41→
 42→  const { chatAgentModel, extractionModel, pmAgentModel, analyticsAgentModel, embeddingModel, observerModel, scorerModel } =
 43→    config.inferenceProvider === "ollama"
 44→      ? createOllamaModels(config, wrap)
 45→      : createOpenRouterModels(config, wrap);
 46→
 47→  const auth = createAuth(surreal, {
 48→    betterAuthSecret: config.betterAuthSecret,
 49→    betterAuthUrl: config.betterAuthUrl,
 50→    githubClientId: config.githubClientId,
 51→    githubClientSecret: config.githubClientSecret,
 52→  });
 53→
 54→  const asSigningKey = await bootstrapSigningKeyFromSurreal(surreal);
 55→
 56→  return {
 57→    surreal,
 58→    analyticsSurreal,
 59→    auth,
 60→    chatAgentModel,
 61→    extractionModel,
 62→    pmAgentModel,
 63→    analyticsAgentModel,
 64→    embeddingModel,
 65→    observerModel,
 66→    scorerModel,
 67→    asSigningKey,
 68→  };
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// OpenRouter model factory
 73→// ---------------------------------------------------------------------------
 74→
 75→function createOpenRouterModels(config: ServerConfig, wrap: (model: any) => any) {
 76→  const openrouter = createOpenRouter({ apiKey: config.openRouterApiKey! });
 77→  const withPlugins = (modelId: string, reasoning = true) =>
 78→    wrap(openrouter(modelId, {
 79→      plugins: [{ id: "response-healing" }],
 80→      ...(reasoning && config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
 81→    }));
 82→
 83→  return {
 84→    chatAgentModel: withPlugins(config.chatAgentModelId),
 85→    extractionModel: withPlugins(config.extractionModelId),
 86→    pmAgentModel: withPlugins(config.pmAgentModelId),
 87→    analyticsAgentModel: withPlugins(config.analyticsAgentModelId, false),
 88→    embeddingModel: openrouter.textEmbeddingModel(config.embeddingModelId),
 89→    observerModel: withPlugins(config.observerModelId),
 90→    scorerModel: withPlugins(config.scorerModelId, false),
 91→  };
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Ollama model factory
 96→// ---------------------------------------------------------------------------
 97→
 98→function createOllamaModels(config: ServerConfig, wrap: (model: any) => any) {
 99→  const ollama = createOllama({ baseURL: `${config.ollamaBaseUrl}/api` });
100→
101→  return {
102→    chatAgentModel: wrap(ollama(config.chatAgentModelId)),
103→    extractionModel: wrap(ollama(config.extractionModelId)),
104→    pmAgentModel: wrap(ollama(config.pmAgentModelId)),
105→    analyticsAgentModel: wrap(ollama(config.analyticsAgentModelId)),
106→    embeddingModel: ollama.embedding(config.embeddingModelId),
107→    observerModel: wrap(ollama(config.observerModelId)),
108→    scorerModel: wrap(ollama(config.scorerModelId)),
109→  };
110→}
