  1→import { join } from "node:path";
  2→import { RecordId, Surreal } from "surrealdb";
  3→
  4→const MIGRATIONS_DIR = join(import.meta.dir, "migrations");
  5→const migrationGlob = new Bun.Glob("*.surql");
  6→
  7→const BOOTSTRAP_SQL = `
  8→DEFINE TABLE IF NOT EXISTS _migration SCHEMAFULL;
  9→DEFINE FIELD IF NOT EXISTS name ON _migration TYPE string;
 10→DEFINE FIELD IF NOT EXISTS applied_at ON _migration TYPE datetime;
 11→`;
 12→
 13→function requireEnv(name: string): string {
 14→  const value = process.env[name];
 15→  if (!value || value.trim().length === 0) {
 16→    throw new Error(`${name} is required`);
 17→  }
 18→  return value.trim();
 19→}
 20→
 21→async function main() {
 22→  const url = requireEnv("SURREAL_URL");
 23→  const username = requireEnv("SURREAL_USERNAME");
 24→  const password = requireEnv("SURREAL_PASSWORD");
 25→  const namespace = requireEnv("SURREAL_NAMESPACE");
 26→  const database = requireEnv("SURREAL_DATABASE");
 27→
 28→  const surreal = new Surreal();
 29→  await surreal.connect(url);
 30→  await surreal.signin({ username, password });
 31→  await surreal.use({ namespace, database });
 32→
 33→  // Bootstrap migration tracking table
 34→  await surreal.query(BOOTSTRAP_SQL);
 35→
 36→  // Read migration files sorted alphabetically
 37→  const files = (await Array.fromAsync(migrationGlob.scan(MIGRATIONS_DIR))).sort();
 38→
 39→  if (files.length === 0) {
 40→    console.log("No migration files found.");
 41→    await surreal.close();
 42→    return;
 43→  }
 44→
 45→  // Get already-applied migrations
 46→  const [applied] = await surreal.query<[Array<{ name: string }>]>(
 47→    "SELECT name FROM _migration;",
 48→  );
 49→  const appliedSet = new Set(applied.map((row) => row.name));
 50→
 51→  const pending = files.filter((f) => !appliedSet.has(f));
 52→
 53→  if (pending.length === 0) {
 54→    console.log("No pending migrations.");
 55→    await surreal.close();
 56→    return;
 57→  }
 58→
 59→  console.log(`${pending.length} pending migration(s):\n`);
 60→
 61→  for (const file of pending) {
 62→    const sql = await Bun.file(join(MIGRATIONS_DIR, file)).text();
 63→
 64→    try {
 65→      const stream = surreal.query(sql).stream();
 66→      let stmtIndex = 0;
 67→      for await (const frame of stream) {
 68→        if ((frame as any).status === "ERR") {
 69→          console.error(`✗ Failed: ${file} (statement ${stmtIndex})`);
 70→          console.error(`  → ${(frame as any).result}`);
 71→          await surreal.close();
 72→          process.exit(1);
 73→        }
 74→        stmtIndex++;
 75→      }
 76→    } catch (err) {
 77→      console.error(`✗ Failed: ${file}`);
 78→      console.error(err);
 79→      await surreal.close();
 80→      process.exit(1);
 81→    }
 82→
 83→    const record = new RecordId("_migration", file);
 84→    await surreal.query("CREATE $record CONTENT { name: $name, applied_at: time::now() };", {
 85→      record,
 86→      name: file,
 87→    });
 88→
 89→    console.log(`✓ Applied: ${file}`);
 90→  }
 91→
 92→  console.log(`\nDone. ${pending.length} migration(s) applied.`);
 93→  await surreal.close();
 94→}
 95→
 96→main().catch((err) => {
 97→  console.error("Migration failed:", err);
 98→  process.exit(1);
 99→});
