  1→import { describe, test, expect, beforeEach, afterEach } from "bun:test";
  2→import { loadServerConfig } from "../../../app/src/server/runtime/config";
  3→
  4→/**
  5→ * Tests for self-hosted deployment config fields:
  6→ * - SELF_HOSTED: boolean, defaults false
  7→ * - ADMIN_EMAIL: required when SELF_HOSTED=true
  8→ * - ADMIN_PASSWORD: required when SELF_HOSTED=true
  9→ * - WORKTREE_MANAGER_ENABLED: boolean, defaults false
 10→ *
 11→ * Behaviors under test:
 12→ * 1. SELF_HOSTED defaults to false when unset
 13→ * 2. SELF_HOSTED parses "true" as true (case-insensitive)
 14→ * 3. ADMIN_EMAIL and ADMIN_PASSWORD required when SELF_HOSTED=true
 15→ * 4. ADMIN_EMAIL and ADMIN_PASSWORD ignored when SELF_HOSTED=false
 16→ * 5. WORKTREE_MANAGER_ENABLED defaults to false when unset
 17→ * 6. WORKTREE_MANAGER_ENABLED parses "true" as true
 18→ * 7. ADMIN_PASSWORD never appears in error messages
 19→ */
 20→
 21→const REQUIRED_ENV = {
 22→  OPENROUTER_API_KEY: "test-key",
 23→  CHAT_AGENT_MODEL: "test-chat-model",
 24→  EXTRACTION_MODEL: "test-extraction-model",
 25→  ANALYTICS_MODEL: "test-analytics-model",
 26→  EMBEDDING_MODEL: "test-embedding-model",
 27→  EMBEDDING_DIMENSION: "1536",
 28→  EXTRACTION_STORE_THRESHOLD: "0.6",
 29→  EXTRACTION_DISPLAY_THRESHOLD: "0.85",
 30→  SURREAL_URL: "ws://127.0.0.1:8000/rpc",
 31→  SURREAL_USERNAME: "root",
 32→  SURREAL_PASSWORD: "root",
 33→  SURREAL_NAMESPACE: "test",
 34→  SURREAL_DATABASE: "test",
 35→  PORT: "3000",
 36→  BETTER_AUTH_SECRET: "test-secret",
 37→  BETTER_AUTH_URL: "http://localhost:3000",
 38→  GITHUB_CLIENT_ID: "test-client-id",
 39→  GITHUB_CLIENT_SECRET: "test-client-secret",
 40→};
 41→
 42→const SELF_HOSTED_VARS = [
 43→  "SELF_HOSTED",
 44→  "ADMIN_EMAIL",
 45→  "ADMIN_PASSWORD",
 46→  "WORKTREE_MANAGER_ENABLED",
 47→] as const;
 48→
 49→describe("self-hosted config parsing", () => {
 50→  let savedEnv: Record<string, string | undefined>;
 51→
 52→  beforeEach(() => {
 53→    savedEnv = { ...Bun.env };
 54→    for (const [key, value] of Object.entries(REQUIRED_ENV)) {
 55→      Bun.env[key] = value;
 56→    }
 57→    for (const key of SELF_HOSTED_VARS) {
 58→      delete Bun.env[key];
 59→    }
 60→  });
 61→
 62→  afterEach(() => {
 63→    for (const key of [...Object.keys(REQUIRED_ENV), ...SELF_HOSTED_VARS]) {
 64→      if (savedEnv[key] !== undefined) {
 65→        Bun.env[key] = savedEnv[key];
 66→      } else {
 67→        delete Bun.env[key];
 68→      }
 69→    }
 70→  });
 71→
 72→  describe("SELF_HOSTED", () => {
 73→    test("defaults to false when unset", () => {
 74→      const config = loadServerConfig();
 75→      expect(config.selfHosted).toBe(false);
 76→    });
 77→
 78→    test("parses 'true' as true", () => {
 79→      Bun.env.SELF_HOSTED = "true";
 80→      Bun.env.ADMIN_EMAIL = "admin@example.com";
 81→      Bun.env.ADMIN_PASSWORD = "secret123";
 82→      const config = loadServerConfig();
 83→      expect(config.selfHosted).toBe(true);
 84→    });
 85→
 86→    test("parses 'TRUE' as true (case-insensitive)", () => {
 87→      Bun.env.SELF_HOSTED = "TRUE";
 88→      Bun.env.ADMIN_EMAIL = "admin@example.com";
 89→      Bun.env.ADMIN_PASSWORD = "secret123";
 90→      const config = loadServerConfig();
 91→      expect(config.selfHosted).toBe(true);
 92→    });
 93→
 94→    test("parses 'false' as false", () => {
 95→      Bun.env.SELF_HOSTED = "false";
 96→      const config = loadServerConfig();
 97→      expect(config.selfHosted).toBe(false);
 98→    });
 99→
100→    test("parses empty string as false", () => {
101→      Bun.env.SELF_HOSTED = "";
102→      const config = loadServerConfig();
103→      expect(config.selfHosted).toBe(false);
104→    });
105→  });
106→
107→  describe("ADMIN_EMAIL and ADMIN_PASSWORD conditional validation", () => {
108→    test("requires ADMIN_EMAIL when SELF_HOSTED=true", () => {
109→      Bun.env.SELF_HOSTED = "true";
110→      Bun.env.ADMIN_PASSWORD = "secret123";
111→      expect(() => loadServerConfig()).toThrow("ADMIN_EMAIL is required when SELF_HOSTED=true");
112→    });
113→
114→    test("requires ADMIN_PASSWORD when SELF_HOSTED=true", () => {
115→      Bun.env.SELF_HOSTED = "true";
116→      Bun.env.ADMIN_EMAIL = "admin@example.com";
117→      expect(() => loadServerConfig()).toThrow("ADMIN_PASSWORD is required when SELF_HOSTED=true");
118→    });
119→
120→    test("returns adminEmail and adminPassword when SELF_HOSTED=true", () => {
121→      Bun.env.SELF_HOSTED = "true";
122→      Bun.env.ADMIN_EMAIL = "admin@example.com";
123→      Bun.env.ADMIN_PASSWORD = "secret123";
124→      const config = loadServerConfig();
125→      expect(config.adminEmail).toBe("admin@example.com");
126→      expect(config.adminPassword).toBe("secret123");
127→    });
128→
129→    test("omits adminEmail and adminPassword when SELF_HOSTED=false", () => {
130→      Bun.env.SELF_HOSTED = "false";
131→      Bun.env.ADMIN_EMAIL = "admin@example.com";
132→      Bun.env.ADMIN_PASSWORD = "secret123";
133→      const config = loadServerConfig();
134→      expect(config.adminEmail).toBeUndefined();
135→      expect(config.adminPassword).toBeUndefined();
136→    });
137→
138→    test("omits adminEmail and adminPassword when SELF_HOSTED unset", () => {
139→      Bun.env.ADMIN_EMAIL = "admin@example.com";
140→      Bun.env.ADMIN_PASSWORD = "secret123";
141→      const config = loadServerConfig();
142→      expect(config.adminEmail).toBeUndefined();
143→      expect(config.adminPassword).toBeUndefined();
144→    });
145→  });
146→
147→  describe("ADMIN_PASSWORD security", () => {
148→    test("error message does not contain the actual password value", () => {
149→      Bun.env.SELF_HOSTED = "true";
150→      // Both missing -- error should mention field name, not leak password
151→      try {
152→        loadServerConfig();
153→      } catch (error) {
154→        const message = (error as Error).message;
155→        expect(message).not.toContain("secret");
156→      }
157→    });
158→  });
159→
160→  describe("WORKTREE_MANAGER_ENABLED", () => {
161→    test("defaults to false when unset", () => {
162→      const config = loadServerConfig();
163→      expect(config.worktreeManagerEnabled).toBe(false);
164→    });
165→
166→    test("parses 'true' as true", () => {
167→      Bun.env.WORKTREE_MANAGER_ENABLED = "true";
168→      const config = loadServerConfig();
169→      expect(config.worktreeManagerEnabled).toBe(true);
170→    });
171→
172→    test("parses 'TRUE' as true (case-insensitive)", () => {
173→      Bun.env.WORKTREE_MANAGER_ENABLED = "TRUE";
174→      const config = loadServerConfig();
175→      expect(config.worktreeManagerEnabled).toBe(true);
176→    });
177→
178→    test("parses empty string as false", () => {
179→      Bun.env.WORKTREE_MANAGER_ENABLED = "";
180→      const config = loadServerConfig();
181→      expect(config.worktreeManagerEnabled).toBe(false);
182→    });
183→  });
184→});
