742→export async function startServer(): Promise<void> {
743→  const config = loadServerConfig();
744→  const runtime = await createRuntimeDependencies(config);
745→  await ensureDefaultWorkspaceProjectScope(runtime.surreal);
746→
747→  const deps: ServerDependencies = {
748→    config,
749→    surreal: runtime.surreal,
750→    analyticsSurreal: runtime.analyticsSurreal,
751→    auth: runtime.auth,
752→    chatAgentModel: runtime.chatAgentModel,
753→    extractionModel: runtime.extractionModel,
754→    pmAgentModel: runtime.pmAgentModel,
755→    analyticsAgentModel: runtime.analyticsAgentModel,
756→    embeddingModel: runtime.embeddingModel,
757→    observerModel: runtime.observerModel,
758→    scorerModel: runtime.scorerModel,
759→    sse: createSseRegistry(),
760→    inflight: createInflightTracker(),
761→    asSigningKey: runtime.asSigningKey,
762→    nonceCache: createNonceCache(),
763→  };
764→
765→  const server = createBrainServer(deps);
766→
767→  // Recover intents stuck in pending_veto with expired windows (fire-and-forget)
768→  const vetoManager = createVetoManager();
769→  deps.inflight.track(
770→    vetoManager.recoverExpiredWindows({
771→      updateStatus: (intentId, status) => updateIntentStatus(deps.surreal, intentId, status),
772→      emitVetoEvent: (event) => logInfo("intent.veto.recovery", "Recovered expired veto window", { event }),
773→      queryExpiredVetoIntents: () => queryExpiredVetoIntents(deps.surreal),
774→    }).catch((err) => {
775→      logError("intent.veto.recovery", "Failed to recover expired veto windows", err);
776→    }),
777→  );
778→
779→  logInfo("server.started", "Brain app server started", {
780→    port: server.port,
781→    host: "127.0.0.1",
782→    chatAgentModelId: config.chatAgentModelId,
783→    extractionModelId: config.extractionModelId,
784→    pmAgentModelId: config.pmAgentModelId,
785→    embeddingModelId: config.embeddingModelId,
786→    embeddingDimension: config.embeddingDimension,
787→    extractionStoreThreshold: config.extractionStoreThreshold,
788→    extractionDisplayThreshold: config.extractionDisplayThreshold,
789→    surrealTransport: detectTransport(config.surrealUrl),
790→    surrealNamespace: config.surrealNamespace,
791→    surrealDatabase: config.surrealDatabase,
792→    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
793→  });
794→}
