 46→export function loadServerConfig(): ServerConfig {
 47→  const inferenceProvider = parseInferenceProvider();
 48→
 49→  const openRouterApiKey = inferenceProvider === "openrouter"
 50→    ? requireEnv("OPENROUTER_API_KEY")
 51→    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;
 52→
 53→  const ollamaBaseUrl = inferenceProvider === "ollama"
 54→    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
 55→    : undefined;
 56→
 57→  const extractionStoreThreshold = parseUnitInterval(
 58→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 59→    "EXTRACTION_STORE_THRESHOLD",
 60→  );
 61→
 62→  const extractionDisplayThreshold = parseUnitInterval(
 63→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 64→    "EXTRACTION_DISPLAY_THRESHOLD",
 65→  );
 66→
 67→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 68→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 69→  }
 70→
 71→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 72→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 73→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
 74→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 75→  const embeddingModelId = requireEnv("EMBEDDING_MODEL");
 76→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 77→
 78→  const surrealUrl = requireEnv("SURREAL_URL");
 79→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 80→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 81→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 82→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 83→
 84→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 85→  const observerModelId = optionalEnv("OBSERVER_MODEL") ?? extractionModelId;
 86→  const scorerModelId = optionalEnv("SCORER_MODEL") ?? extractionModelId;
 87→  const githubWebhookSecret = optionalEnv("GITHUB_WEBHOOK_SECRET");
 88→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 89→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 90→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 91→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 92→  const anthropicApiUrl = optionalEnv("ANTHROPIC_API_URL") ?? "https://api.anthropic.com";
 93→  const anthropicApiKey = optionalEnv("ANTHROPIC_API_KEY");
 94→
 95→  const openRouterReasoning = inferenceProvider === "openrouter"
 96→    ? parseOpenRouterReasoning()
 97→    : undefined;
 98→
 99→  const selfHosted = parseBooleanEnv("SELF_HOSTED");
100→  const worktreeManagerEnabled = parseBooleanEnv("WORKTREE_MANAGER_ENABLED");
101→
102→  const adminEmail = selfHosted
103→    ? requireSelfHostedEnv("ADMIN_EMAIL")
104→    : undefined;
105→  const adminPassword = selfHosted
106→    ? requireSelfHostedEnv("ADMIN_PASSWORD")
107→    : undefined;
108→
109→  return {
110→    inferenceProvider,
111→    ...(openRouterApiKey ? { openRouterApiKey } : {}),
112→    ...(ollamaBaseUrl ? { ollamaBaseUrl } : {}),
113→    chatAgentModelId,
114→    extractionModelId,
115→    pmAgentModelId,
116→    analyticsAgentModelId,
117→    embeddingModelId,
118→    embeddingDimension,
119→    extractionStoreThreshold,
120→    extractionDisplayThreshold,
121→    ...(openRouterReasoning ? { openRouterReasoning } : {}),
122→    surrealUrl,
123→    surrealUsername,
124→    surrealPassword,
125→    surrealNamespace,
126→    surrealDatabase,
127→    port,
128→    observerModelId,
129→    scorerModelId,
130→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
131→    betterAuthSecret,
132→    betterAuthUrl,
133→    githubClientId,
134→    githubClientSecret,
135→    anthropicApiUrl,
136→    ...(anthropicApiKey ? { anthropicApiKey } : {}),
137→    selfHosted,
138→    ...(adminEmail ? { adminEmail } : {}),
139→    ...(adminPassword ? { adminPassword } : {}),
140→    worktreeManagerEnabled,
141→  };
142→}
