144→function optionalEnv(name: string): string | undefined {
145→  const value = Bun.env[name]?.trim();
146→  if (!value || value.length === 0) return undefined;
147→  return value;
148→}
149→
150→function requireEnv(name: string): string {
151→  const value = Bun.env[name];
152→  if (!value || value.trim().length === 0) {
153→    throw new Error(`${name} is required`);
154→  }
155→
156→  return value;
157→}
158→
159→function parsePositiveInteger(value: string, envName: string): number {
160→  const parsed = Number(value);
161→  if (!Number.isInteger(parsed) || parsed < 1) {
162→    throw new Error(`${envName} must be a positive integer`);
163→  }
164→  return parsed;
165→}
166→
167→function parseUnitInterval(value: string, envName: string): number {
168→  const parsed = Number(value);
169→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
170→    throw new Error(`${envName} must be a number between 0 and 1`);
171→  }
172→
173→  return parsed;
174→}
175→
176→function parseInferenceProvider(): InferenceProvider {
177→  const value = Bun.env.INFERENCE_PROVIDER?.trim().toLowerCase();
178→  if (!value || value === "openrouter") return "openrouter";
179→  if (value === "ollama") return "ollama";
180→  throw new Error("INFERENCE_PROVIDER must be one of: openrouter, ollama");
181→}
182→
183→function parseBooleanEnv(name: string): boolean {
184→  const value = Bun.env[name]?.trim().toLowerCase();
185→  return value === "true";
186→}
187→
188→function requireSelfHostedEnv(name: string): string {
189→  const value = Bun.env[name]?.trim();
190→  if (!value || value.length === 0) {
191→    throw new Error(`${name} is required when SELF_HOSTED=true`);
192→  }
193→  return value;
194→}
195→
196→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
197→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
198→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
199→
200→  if (!effortValue && !maxTokensValue) {
201→    return undefined;
202→  }
203→
204→  const reasoning: OpenRouterReasoningOptions = {};
205→
206→  if (effortValue) {
207→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
208→
209→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
210→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
211→    }
212→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
213→  }
214→
215→  if (maxTokensValue) {
216→    const parsed = Number(maxTokensValue);
217→    if (!Number.isFinite(parsed) || parsed < 1) {
218→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
219→    }
220→    reasoning.max_tokens = parsed;
221→  }
222→
223→  return reasoning;
224→}
