 1→import { useEffect, useState } from "react";
 2→
 3→export type PublicConfig = {
 4→  selfHosted: boolean;
 5→  worktreeManagerEnabled: boolean;
 6→};
 7→
 8→const DEFAULT_CONFIG: PublicConfig = {
 9→  selfHosted: false,
10→  worktreeManagerEnabled: false,
11→};
12→
13→export const CONFIG_URL = "/api/config";
14→
15→export function parseConfigResponse(data: unknown): PublicConfig {
16→  if (
17→    typeof data === "object" &&
18→    data !== null &&
19→    "selfHosted" in data &&
20→    typeof (data as Record<string, unknown>).selfHosted === "boolean"
21→  ) {
22→    const record = data as Record<string, unknown>;
23→    return {
24→      selfHosted: record.selfHosted as boolean,
25→      worktreeManagerEnabled:
26→        typeof record.worktreeManagerEnabled === "boolean"
27→          ? record.worktreeManagerEnabled
28→          : false,
29→    };
30→  }
31→  return DEFAULT_CONFIG;
32→}
33→
34→export function usePublicConfig(): {
35→  config: PublicConfig;
36→  isLoading: boolean;
37→} {
38→  const [config, setConfig] = useState<PublicConfig>(DEFAULT_CONFIG);
39→  const [isLoading, setIsLoading] = useState(true);
40→
41→  useEffect(() => {
42→    let cancelled = false;
43→
44→    fetch(CONFIG_URL)
45→      .then((response) => {
46→        if (!response.ok) return DEFAULT_CONFIG;
47→        return response.json() as Promise<unknown>;
48→      })
49→      .then((data) => {
50→        if (!cancelled) {
51→          setConfig(parseConfigResponse(data));
52→        }
53→      })
54→      .catch(() => {
55→        if (!cancelled) {
56→          setConfig(DEFAULT_CONFIG);
57→        }
58→      })
59→      .finally(() => {
60→        if (!cancelled) {
61→          setIsLoading(false);
62→        }
63→      });
64→
65→    return () => {
66→      cancelled = true;
67→    };
68→  }, []);
69→
70→  return { config, isLoading };
71→}
72→

