 75→
 76→function createOpenRouterModels(config: ServerConfig, wrap: (model: any) => any) {
 77→  const openrouter = createOpenRouter({ apiKey: config.openRouterApiKey! });
 78→  const withPlugins = (modelId: string, reasoning = true) =>
 79→    wrap(openrouter(modelId, {
 80→      plugins: [{ id: "response-healing" }],
 81→      ...(reasoning && config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
 82→    }));
 83→
 84→  return {
 85→    chatAgentModel: withPlugins(config.chatAgentModelId),
 86→    extractionModel: withPlugins(config.extractionModelId),
 87→    pmAgentModel: withPlugins(config.pmAgentModelId),
 88→    analyticsAgentModel: withPlugins(config.analyticsAgentModelId, false),
