  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→import { usePublicConfig } from "../../hooks/use-public-config";
 14→import { AgentSessionPanel } from "./AgentSessionPanel";
 15→import { Button } from "../ui/button";
 16→import { Input } from "../ui/input";
 17→import { Badge } from "../ui/badge";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Pure core: view derivation
 21→// ---------------------------------------------------------------------------
 22→
 23→const ASSIGNABLE_STATUSES = new Set(["ready", "todo"]);
 24→
 25→export type AgentStatusViewHidden = { variant: "hidden" };
 26→export type AgentStatusViewAssign = { variant: "assign" };
 27→export type AgentStatusViewActive = {
 28→  variant: "active";
 29→  agentSessionId: string;
 30→  orchestratorStatus: string;
 31→  filesChangedCount: number;
 32→  streamUrl: string;
 33→  startedAt: string;
 34→};
 35→
 36→export type AgentStatusView =
 37→  | AgentStatusViewHidden
 38→  | AgentStatusViewAssign
 39→  | AgentStatusViewActive;
 40→
 41→export type DeriveAgentStatusInput = {
 42→  entityKind: string;
 43→  entityStatus: string;
 44→  agentSession?: AgentSessionSummary;
 45→};
 46→
 47→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 48→  if (input.entityKind !== "task") {
 49→    return { variant: "hidden" };
 50→  }
 51→
 52→  if (input.agentSession) {
 53→    return {
 54→      variant: "active",
 55→      agentSessionId: input.agentSession.agentSessionId,
 56→      orchestratorStatus: input.agentSession.orchestratorStatus,
 57→      filesChangedCount: input.agentSession.filesChangedCount,
 58→      streamUrl: `/api/orchestrator/stream/${encodeURIComponent(input.agentSession.streamId)}`,
 59→      startedAt: input.agentSession.startedAt,
 60→    };
 61→  }
 62→
 63→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 64→    return { variant: "assign" };
 65→  }
 66→
 67→  return { variant: "hidden" };
 68→}
 69→
 70→// ---------------------------------------------------------------------------
 71→// Repo path banner visibility
 72→// ---------------------------------------------------------------------------
 73→
 74→export function shouldShowRepoPathBanner(input: {
 75→  worktreeManagerEnabled: boolean;
 76→  repoPath: string | undefined;
 77→}): boolean {
 78→  if (!input.worktreeManagerEnabled) return false;
 79→  return input.repoPath === undefined;
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Status badge display
 84→// ---------------------------------------------------------------------------
 85→
 86→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 87→  spawning: "Spawning",
 88→  active: "Working",
 89→  idle: "Idle",
 90→  completed: "Completed",
 91→  aborted: "Aborted",
 92→  error: "Error",
 93→};
 94→
 95→const STATUS_VARIANTS: Record<AgentSessionStatus, "default" | "secondary" | "destructive" | "outline"> = {
 96→  spawning: "outline",
 97→  active: "default",
 98→  idle: "secondary",
 99→  completed: "secondary",
100→  aborted: "destructive",
101→  error: "destructive",
102→};
103→
104→function statusLabel(status: AgentSessionStatus): string {
105→  return STATUS_LABELS[status];
106→}
107→
108→// ---------------------------------------------------------------------------
109→// Component
110→// ---------------------------------------------------------------------------
111→
112→export function AgentStatusSection({
113→  entityId,
114→  workspaceId,
115→  entityKind,
116→  entityStatus,
117→  agentSession,
118→}: {
119→  entityId: string;
120→  workspaceId: string;
121→  entityKind: EntityKind;
122→  entityStatus: string;
123→  agentSession?: AgentSessionSummary;
124→}) {
125→  const repoPath = useWorkspaceState((s) => s.repoPath);
126→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
127→  const { config } = usePublicConfig();
128→  const [assigning, setAssigning] = useState(false);
129→  const [assignError, setAssignError] = useState<string | undefined>();
130→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
131→  const [repoPathInput, setRepoPathInput] = useState("");
132→  const [settingRepoPath, setSettingRepoPath] = useState(false);
133→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
134→
135→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
136→
137→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
138→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
139→
140→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
141→
142→  const hasActiveStream = streamUrl !== undefined;
143→
144→  if (initialView.variant === "hidden" && !hasActiveStream) {
145→    return undefined;
146→  }
147→
148→  async function handleAssign() {
149→    if (assigning) return;
150→    setAssigning(true);
151→    setAssignError(undefined);
152→    try {
153→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
154→      const result = await assignAgent(workspaceId, rawTaskId);
155→      setAssignResult(result);
156→    } catch (err) {
157→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
158→    } finally {
159→      setAssigning(false);
160→    }
161→  }
162→
163→  if (hasActiveStream) {
164→    const displayStatus = sessionState.status;
165→    const displayFiles = initialView.variant === "active"
166→      ? initialView.filesChangedCount + sessionState.filesChanged
167→      : sessionState.filesChanged;
168→
169→    const currentSessionId = assignResult?.agentSessionId
170→      ?? (initialView.variant === "active" ? initialView.agentSessionId : "");
171→
172→    return (
173→      <div className="flex flex-col gap-2 px-4">
174→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
175→        <div className="flex items-center gap-2">
176→          <Badge variant={STATUS_VARIANTS[displayStatus]} data-testid="agent-status-badge">
177→            {statusLabel(displayStatus)}
178→          </Badge>
179→          {displayFiles > 0 ? (
180→            <span className="text-xs text-muted-foreground" data-testid="agent-file-count">
181→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
182→            </span>
183→          ) : undefined}
184→        </div>
185→        <AgentSessionPanel
186→          workspaceId={workspaceId}
187→          agentSessionId={currentSessionId}
188→          sessionStatus={displayStatus}
189→          outputEntries={sessionState.outputEntries}
190→          stallWarning={sessionState.stallWarning}
191→          connectionError={sessionState.connectionError}
192→        />
193→        {displayStatus === "idle" ? (
194→          <a
195→            className="text-xs font-medium text-ring hover:underline"
196→            data-testid="agent-review-link"
197→            href={`/review/${encodeURIComponent(currentSessionId)}`}
198→          >
199→            Review
200→          </a>
201→        ) : undefined}
202→      </div>
203→    );
204→  }
205→
206→  if (initialView.variant === "assign") {
207→    const missingRepoPath = shouldShowRepoPathBanner({
208→      worktreeManagerEnabled: config.worktreeManagerEnabled,
209→      repoPath,
210→    });
211→
212→    return (
213→      <div className="flex flex-col gap-2 px-4">
214→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
215→        {missingRepoPath ? (
216→          <div className="flex flex-col gap-2 rounded-md border border-border bg-muted p-3" data-testid="agent-repo-path-banner">
217→            <p className="text-xs text-muted-foreground">Repository path is not configured for this workspace. Set it before assigning an agent.</p>
218→            <form
219→              className="flex items-center gap-1.5"
220→              data-testid="agent-repo-path-form"
221→              onSubmit={async (e) => {
222→                e.preventDefault();
223→                const trimmed = repoPathInput.trim();
224→                if (!trimmed || settingRepoPath) return;
225→                setSettingRepoPath(true);
226→                setRepoPathError(undefined);
227→                try {
228→                  const res = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/repo-path`, {
229→                    method: "POST",
230→                    headers: { "Content-Type": "application/json" },
231→                    body: JSON.stringify({ path: trimmed }),
232→                  });
233→                  if (!res.ok) {
234→                    const body = await res.json().catch(() => ({ error: "Failed to set repository path" }));
235→                    setRepoPathError(body.error ?? "Failed to set repository path");
236→                    return;
237→                  }
238→                  setStoreRepoPath(trimmed);
239→                  setRepoPathInput("");
240→                } catch {
241→                  setRepoPathError("Network error");
242→                } finally {
243→                  setSettingRepoPath(false);
244→                }
245→              }}
246→            >
247→              <Input
248→                type="text"
249→                data-testid="agent-repo-path-input"
250→                placeholder="/path/to/git/repository"
251→                value={repoPathInput}
252→                onChange={(e) => setRepoPathInput(e.target.value)}
253→                disabled={settingRepoPath}
254→                className="h-7 flex-1 text-xs"
255→              />
256→              <Button
257→                type="submit"
258→                size="xs"
259→                data-testid="agent-repo-path-action"
260→                disabled={settingRepoPath || repoPathInput.trim().length === 0}
261→              >
262→                {settingRepoPath ? "Setting..." : "Set Path"}
263→              </Button>
264→            </form>
265→            {repoPathError ? (
266→              <p className="text-xs text-destructive" data-testid="agent-repo-path-error">{repoPathError}</p>
267→            ) : undefined}
268→          </div>
269→        ) : undefined}
270→        <Button
271→          variant="outline"
272→          size="sm"
273→          data-testid="agent-assign-button"
274→          disabled={assigning || missingRepoPath}
275→          onClick={handleAssign}
276→        >
277→          {assigning ? "Assigning..." : "Assign Agent"}
278→        </Button>
279→        {assignError ? (
280→          <p className="text-xs text-destructive" data-testid="agent-assign-error">{assignError}</p>
281→        ) : undefined}
282→      </div>
283→    );
284→  }
285→
286→  return undefined;
287→}
