  1→import { useState } from "react";
  2→import { useSearch, useNavigate } from "@tanstack/react-router";
  3→import { signIn, signUp, useSession } from "../lib/auth-client";
  4→import { usePublicConfig } from "../hooks/use-public-config";
  5→import { Button } from "../components/ui/button";
  6→import { Input } from "../components/ui/input";
  7→import { Separator } from "../components/ui/separator";
  8→
  9→export function SignInPage() {
 10→  const { data: session, isPending } = useSession();
 11→  const navigate = useNavigate();
 12→  const search = useSearch({ strict: false }) as Record<string, string>;
 13→  const { config } = usePublicConfig();
 14→
 15→  const signupAllowed = !config.selfHosted;
 16→  const [mode, setMode] = useState<"signin" | "signup">("signin");
 17→  const effectiveMode = signupAllowed ? mode : "signin";
 18→  const [email, setEmail] = useState("");
 19→  const [password, setPassword] = useState("");
 20→  const [name, setName] = useState("");
 21→  const [error, setError] = useState("");
 22→  const [loading, setLoading] = useState(false);
 23→
 24→  if (!isPending && session) {
 25→    const redirectTo = search.redirectTo ?? "/";
 26→    void navigate({ to: redirectTo });
 27→    return undefined;
 28→  }
 29→
 30→  function getPostLoginRedirect(): string {
 31→    const { redirectTo, ...oauthParams } = search;
 32→    if (redirectTo) return redirectTo;
 33→    if (oauthParams.client_id || oauthParams.sig) {
 34→      const params = new URLSearchParams(oauthParams);
 35→      return `/api/auth/oauth2/authorize?${params.toString()}`;
 36→    }
 37→    return "/";
 38→  }
 39→
 40→  async function handleSubmit(e: React.FormEvent) {
 41→    e.preventDefault();
 42→    setError("");
 43→    setLoading(true);
 44→
 45→    try {
 46→      if (effectiveMode === "signup") {
 47→        const result = await signUp.email({ email, password, name });
 48→        if (result.error) {
 49→          setError(result.error.message ?? "Sign up failed");
 50→          setLoading(false);
 51→          return;
 52→        }
 53→      } else {
 54→        const result = await signIn.email({ email, password });
 55→        if (result.error) {
 56→          setError(result.error.message ?? "Invalid credentials");
 57→          setLoading(false);
 58→          return;
 59→        }
 60→      }
 61→      window.location.href = getPostLoginRedirect();
 62→    } catch (err) {
 63→      setError(err instanceof Error ? err.message : "Authentication failed");
 64→      setLoading(false);
 65→    }
 66→  }
 67→
 68→  async function handleGitHub() {
 69→    setError("");
 70→    await signIn.social({
 71→      provider: "github",
 72→      callbackURL: getPostLoginRedirect(),
 73→    });
 74→  }
 75→
 76→  if (isPending) {
 77→    return (
 78→      <div className="flex h-screen items-center justify-center bg-background">
 79→        <div className="w-full max-w-sm rounded-xl border border-border bg-card p-6">
 80→          <p className="text-sm text-muted-foreground">Loading...</p>
 81→        </div>
 82→      </div>
 83→    );
 84→  }
 85→
 86→  return (
 87→    <div className="flex h-screen items-center justify-center bg-background">
 88→      <div className="flex w-full max-w-sm flex-col gap-4 rounded-xl border border-border bg-card p-6">
 89→        <h1 className="text-center text-xl font-bold text-accent">Brain</h1>
 90→        <p className="text-center text-sm text-muted-foreground">
 91→          {effectiveMode === "signin" ? "Sign in to your workspace" : "Create an account"}
 92→        </p>
 93→
 94→        <form onSubmit={handleSubmit} className="flex flex-col gap-3">
 95→          {effectiveMode === "signup" && (
 96→            <Input
 97→              type="text"
 98→              placeholder="Name"
 99→              value={name}
100→              onChange={(e) => setName(e.target.value)}
101→              required
102→            />
103→          )}
104→          <Input
105→            type="email"
106→            placeholder="Email"
107→            value={email}
108→            onChange={(e) => setEmail(e.target.value)}
