114→            value={password}
115→            onChange={(e) => setPassword(e.target.value)}
116→            required
117→            minLength={8}
118→          />
119→
120→          {error && <p className="text-sm text-destructive">{error}</p>}
121→
122→          <Button type="submit" disabled={loading}>
123→            {loading ? "..." : effectiveMode === "signin" ? "Sign in" : "Create account"}
124→          </Button>
125→        </form>
126→
127→        <div className="flex items-center gap-3">
128→          <Separator className="flex-1" />
129→          <span className="text-xs text-muted-foreground">or</span>
130→          <Separator className="flex-1" />
131→        </div>
132→
133→        <Button variant="outline" onClick={handleGitHub}>
134→          Sign in with GitHub
135→        </Button>
136→
137→        {signupAllowed && (
138→          <p className="text-center text-xs text-muted-foreground">
139→            {effectiveMode === "signin" ? (
140→              <>
141→                No account?{" "}
142→                <button type="button" className="text-ring hover:underline" onClick={() => { setMode("signup"); setError(""); }}>
143→                  Create one
144→                </button>
145→              </>
146→            ) : (
147→              <>
148→                Already have an account?{" "}
149→                <button type="button" className="text-ring hover:underline" onClick={() => { setMode("signin"); setError(""); }}>
150→                  Sign in
151→                </button>
152→              </>
153→            )}
154→          </p>
155→        )}
156→      </div>
157→    </div>
158→  );
159→}
