743→function detectTransport(url: string): string {
744→  if (url.startsWith("wss://")) return "wss";
745→  if (url.startsWith("ws://")) return "ws";
746→  if (url.startsWith("https://")) return "https";
747→  return "http";
748→}
749→
750→export async function startServer(): Promise<void> {
751→  const config = loadServerConfig();
752→  const runtime = await createRuntimeDependencies(config);
753→  await ensureDefaultWorkspaceProjectScope(runtime.surreal);
754→
755→  const deps: ServerDependencies = {
756→    config,
757→    surreal: runtime.surreal,
758→    analyticsSurreal: runtime.analyticsSurreal,
759→    auth: runtime.auth,
760→    chatAgentModel: runtime.chatAgentModel,
761→    extractionModel: runtime.extractionModel,
762→    pmAgentModel: runtime.pmAgentModel,
763→    analyticsAgentModel: runtime.analyticsAgentModel,
764→    embeddingModel: runtime.embeddingModel,
765→    observerModel: runtime.observerModel,
766→    scorerModel: runtime.scorerModel,
767→    sse: createSseRegistry(),
768→    inflight: createInflightTracker(),
769→    asSigningKey: runtime.asSigningKey,
770→    nonceCache: createNonceCache(),
771→  };
772→
773→  const server = createBrainServer(deps);
774→
775→  // Recover intents stuck in pending_veto with expired windows (fire-and-forget)
776→  const vetoManager = createVetoManager();
777→  deps.inflight.track(
778→    vetoManager.recoverExpiredWindows({
779→      updateStatus: (intentId, status) => updateIntentStatus(deps.surreal, intentId, status),
780→      emitVetoEvent: (event) => logInfo("intent.veto.recovery", "Recovered expired veto window", { event }),
781→      queryExpiredVetoIntents: () => queryExpiredVetoIntents(deps.surreal),
782→    }).catch((err) => {
783→      logError("intent.veto.recovery", "Failed to recover expired veto windows", err);
784→    }),
785→  );
786→
787→  logInfo("server.started", "Brain app server started", {
788→    port: server.port,
789→    host: "127.0.0.1",
790→    chatAgentModelId: config.chatAgentModelId,
791→    extractionModelId: config.extractionModelId,
792→    pmAgentModelId: config.pmAgentModelId,
793→    embeddingModelId: config.embeddingModelId,
794→    embeddingDimension: config.embeddingDimension,
795→    extractionStoreThreshold: config.extractionStoreThreshold,
796→    extractionDisplayThreshold: config.extractionDisplayThreshold,
797→    surrealTransport: detectTransport(config.surrealUrl),
798→    surrealNamespace: config.surrealNamespace,
799→    surrealDatabase: config.surrealDatabase,
800→    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
801→  });
802→}
