105→    pmAgentModel: wrap(ollama(config.pmAgentModelId)),
106→    analyticsAgentModel: wrap(ollama(config.analyticsAgentModelId)),
107→    embeddingModel: ollama.embedding(config.embeddingModelId),
108→    observerModel: wrap(ollama(config.observerModelId)),
109→    scorerModel: wrap(ollama(config.scorerModelId)),
110→  };
111→}
