 63→export function createAuth(surreal: Surreal, config: AuthConfig) {
 64→  const allScopes = [
 65→    "openid",
 66→    "profile",
 67→    "email",
 68→    "offline_access",
 69→    ...Object.keys(BRAIN_SCOPES),
 70→  ];
 71→
 72→  const signupGuard = buildSignupGuard(config.selfHosted);
 73→
 74→  return betterAuth({
 75→    secret: config.betterAuthSecret,
 76→    baseURL: config.betterAuthUrl,
 77→    basePath: "/api/auth",
 78→    database: surrealdbAdapter(surreal),
 79→    ...(signupGuard ? { databaseHooks: signupGuard } : {}),
 80→    user: {
 81→      modelName: "person",
 82→      fields: {
 83→        email: "contact_email",
 84→        emailVerified: "email_verified",
 85→        createdAt: "created_at",
 86→        updatedAt: "updated_at",
 87→      },
 88→    },
 89→    session: {
 90→      storeSessionInDatabase: true,
 91→      fields: {
 92→        userId: "person_id",
 93→        expiresAt: "expires_at",
 94→        ipAddress: "ip_address",
 95→        userAgent: "user_agent",
 96→        createdAt: "created_at",
 97→        updatedAt: "updated_at",
 98→      },
 99→    },
100→    account: {
101→      fields: {
102→        userId: "person_id",
103→        accountId: "account_id",
104→        providerId: "provider_id",
105→        accessToken: "access_token",
106→        refreshToken: "refresh_token",
107→        accessTokenExpiresAt: "access_token_expires_at",
108→        refreshTokenExpiresAt: "refresh_token_expires_at",
109→        idToken: "id_token",
110→        createdAt: "created_at",
111→        updatedAt: "updated_at",
112→      },
113→    },
114→    verification: {
115→      fields: {
116→        expiresAt: "expires_at",
117→        createdAt: "created_at",
118→        updatedAt: "updated_at",
119→      },
120→    },
121→    emailAndPassword: buildEmailAndPasswordConfig(config.selfHosted),
122→    socialProviders: {
123→      github: {
124→        clientId: config.githubClientId,
125→        clientSecret: config.githubClientSecret,
126→      },
127→    },
128→    plugins: [
129→      jwt(),
130→      oauthProvider({
131→        loginPage: "/sign-in",
132→        consentPage: "/consent",
133→        scopes: allScopes,
134→        validAudiences: [config.betterAuthUrl],
135→        allowDynamicClientRegistration: true,
136→        allowUnauthenticatedClientRegistration: true,
137→        accessTokenExpiresIn: 3600,
138→        refreshTokenExpiresIn: 2592000,
139→        customAccessTokenClaims: async ({ user }) => {
140→          if (!user) return {};
141→          const [memberRows] = await surreal.query<
142→            [Array<{ workspace_id: RecordId<"workspace", string>; workspace_name: string }>]
143→          >(
144→            `SELECT out.id AS workspace_id, out.name AS workspace_name
145→             FROM member_of
146→             WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person)
147→             LIMIT 1;`,
148→            { person: new RecordId("person", user.id) },
149→          );
150→
151→          if (memberRows.length === 0) {
152→            return {};
153→          }
154→
155→          return {
156→            "urn:brain:workspace": memberRows[0].workspace_id.id as string,
157→            "urn:brain:workspace_name": memberRows[0].workspace_name,
158→            "urn:brain:agent_type": "code_agent",
159→          };
160→        },
161→      }),
162→    ],
163→  });
164→}
