780→      emitVetoEvent: (event) => logInfo("intent.veto.recovery", "Recovered expired veto window", { event }),
781→      queryExpiredVetoIntents: () => queryExpiredVetoIntents(deps.surreal),
782→    }).catch((err) => {
783→      logError("intent.veto.recovery", "Failed to recover expired veto windows", err);
784→    }),
785→  );
786→
787→  logInfo("server.started", "Brain app server started", {
788→    port: server.port,
789→    host: "127.0.0.1",
790→    chatAgentModelId: config.chatAgentModelId,
791→    extractionModelId: config.extractionModelId,
792→    pmAgentModelId: config.pmAgentModelId,
793→    embeddingModelId: config.embeddingModelId,
794→    embeddingDimension: config.embeddingDimension,
795→    extractionStoreThreshold: config.extractionStoreThreshold,
796→    extractionDisplayThreshold: config.extractionDisplayThreshold,
797→    surrealTransport: detectTransport(config.surrealUrl),
798→    surrealNamespace: config.surrealNamespace,
