  1→import { describe, test, expect, beforeEach, afterEach } from "bun:test";
  2→import { loadServerConfig } from "../../../app/src/server/runtime/config";
  3→
  4→/**
  5→ * Tests for self-hosted deployment config fields:
  6→ * - SELF_HOSTED: boolean, defaults false
  7→ * - ADMIN_EMAIL: required when SELF_HOSTED=true
  8→ * - ADMIN_PASSWORD: required when SELF_HOSTED=true
  9→ * - WORKTREE_MANAGER_ENABLED: boolean, defaults false
 10→ *
 11→ * Behaviors under test:
 12→ * 1. SELF_HOSTED defaults to false when unset
 13→ * 2. SELF_HOSTED parses "true" as true (case-insensitive)
 14→ * 3. ADMIN_EMAIL and ADMIN_PASSWORD required when SELF_HOSTED=true
 15→ * 4. ADMIN_EMAIL and ADMIN_PASSWORD ignored when SELF_HOSTED=false
 16→ * 5. WORKTREE_MANAGER_ENABLED defaults to false when unset
 17→ * 6. WORKTREE_MANAGER_ENABLED parses "true" as true
 18→ * 7. ADMIN_PASSWORD never appears in error messages
 19→ */
 20→
 21→const REQUIRED_ENV = {
 22→  OPENROUTER_API_KEY: "test-key",
 23→  CHAT_AGENT_MODEL: "test-chat-model",
 24→  EXTRACTION_MODEL: "test-extraction-model",
 25→  ANALYTICS_MODEL: "test-analytics-model",
 26→  EMBEDDING_MODEL: "test-embedding-model",
 27→  EMBEDDING_DIMENSION: "1536",
 28→  EXTRACTION_STORE_THRESHOLD: "0.6",
 29→  EXTRACTION_DISPLAY_THRESHOLD: "0.85",
 30→  SURREAL_URL: "ws://127.0.0.1:8000/rpc",
 31→  SURREAL_USERNAME: "root",
 32→  SURREAL_PASSWORD: "root",
 33→  SURREAL_NAMESPACE: "test",
 34→  SURREAL_DATABASE: "test",
 35→  PORT: "3000",
 36→  BETTER_AUTH_SECRET: "test-secret",
 37→  BETTER_AUTH_URL: "http://localhost:3000",
 38→  GITHUB_CLIENT_ID: "test-client-id",
 39→  GITHUB_CLIENT_SECRET: "test-client-secret",
 40→};
 41→
 42→const SELF_HOSTED_VARS = [
 43→  "SELF_HOSTED",
 44→  "ADMIN_EMAIL",
 45→  "ADMIN_PASSWORD",
 46→  "WORKTREE_MANAGER_ENABLED",
 47→] as const;
 48→
 49→describe("self-hosted config parsing", () => {
 50→  let savedEnv: Record<string, string | undefined>;
 51→
 52→  beforeEach(() => {
 53→    savedEnv = { ...Bun.env };
 54→    for (const [key, value] of Object.entries(REQUIRED_ENV)) {
 55→      Bun.env[key] = value;
 56→    }
 57→    for (const key of SELF_HOSTED_VARS) {
 58→      delete Bun.env[key];
 59→    }
 60→  });
 61→
 62→  afterEach(() => {
 63→    for (const key of [...Object.keys(REQUIRED_ENV), ...SELF_HOSTED_VARS]) {
 64→      if (savedEnv[key] !== undefined) {
 65→        Bun.env[key] = savedEnv[key];
 66→      } else {
 67→        delete Bun.env[key];
 68→      }
 69→    }
 70→  });
 71→
 72→  describe("SELF_HOSTED", () => {
 73→    test("defaults to false when unset", () => {
 74→      const config = loadServerConfig();
 75→      expect(config.selfHosted).toBe(false);
 76→    });
 77→
 78→    test("parses 'true' as true", () => {
 79→      Bun.env.SELF_HOSTED = "true";
 80→      Bun.env.ADMIN_EMAIL = "admin@example.com";
 81→      Bun.env.ADMIN_PASSWORD = "secret123";
 82→      const config = loadServerConfig();
 83→      expect(config.selfHosted).toBe(true);
 84→    });
 85→
 86→    test("parses 'TRUE' as true (case-insensitive)", () => {
 87→      Bun.env.SELF_HOSTED = "TRUE";
 88→      Bun.env.ADMIN_EMAIL = "admin@example.com";
 89→      Bun.env.ADMIN_PASSWORD = "secret123";
 90→      const config = loadServerConfig();
 91→      expect(config.selfHosted).toBe(true);
 92→    });
