  1→import { join } from "node:path";
  2→import { RecordId, Surreal } from "surrealdb";
  3→
  4→// --- Admin seed types and pure functions (exported for testing) ---
  5→
  6→export type AdminSeedConfig = {
  7→  email: string;
  8→  password: string;
  9→};
 10→
 11→export function parseSeedConfig(
 12→  env: Record<string, string | undefined>,
 13→): AdminSeedConfig | undefined {
 14→  const selfHosted = env.SELF_HOSTED?.trim().toLowerCase() === "true";
 15→  if (!selfHosted) return undefined;
 16→
 17→  const email = env.ADMIN_EMAIL?.trim();
 18→  const password = env.ADMIN_PASSWORD;
 19→  if (!email) return undefined;
 20→  if (!password) return undefined;
 21→
 22→  return { email, password };
 23→}
 24→
 25→export function buildPersonRecord(
 26→  email: string,
 27→  now: Date,
 28→): {
 29→  name: string;
 30→  contact_email: string;
 31→  email_verified: boolean;
 32→  created_at: Date;
 33→  updated_at: Date;
 34→} {
 35→  return {
 36→    name: "Admin",
 37→    contact_email: email,
 38→    email_verified: true,
 39→    created_at: now,
 40→    updated_at: now,
 41→  };
 42→}
 43→
 44→export function buildAccountRecord(
 45→  personId: string,
 46→  hashedPassword: string,
 47→  now: Date,
 48→): {
 49→  account_id: string;
 50→  provider_id: string;
 51→  password: string;
 52→  created_at: Date;
 53→  updated_at: Date;
 54→} {
 55→  return {
 56→    account_id: personId,
 57→    provider_id: "credential",
 58→    password: hashedPassword,
 59→    created_at: now,
 60→    updated_at: now,
 61→  };
 62→}
 63→
 64→async function seedAdminUser(
 65→  surreal: Surreal,
 66→  config: AdminSeedConfig,
 67→): Promise<void> {
 68→  const [existing] = await surreal.query<[Array<{ id: RecordId }>]>(
 69→    "SELECT id FROM person WHERE contact_email = $email LIMIT 1;",
 70→    { email: config.email },
 71→  );
 72→
 73→  if (existing.length > 0) {
 74→    console.log(`Admin user already exists, skipping seed`);
 75→    return;
 76→  }
 77→
 78→  const hashedPassword = await Bun.password.hash(config.password);
 79→  const now = new Date();
 80→
 81→  const personContent = buildPersonRecord(config.email, now);
 82→  const [createdPersons] = await surreal.query<[Array<{ id: RecordId }>]>(
 83→    "CREATE person CONTENT $content;",
 84→    { content: personContent },
 85→  );
 86→  const personRecord = createdPersons[0];
 87→  const personId = personRecord.id.id as string;
 88→
 89→  const accountContent = buildAccountRecord(personId, hashedPassword, now);
 90→  await surreal.query(
 91→    "CREATE $record CONTENT $content;",
 92→    {
 93→      record: new RecordId("account", personId),
 94→      content: {
 95→        ...accountContent,
 96→        person_id: personRecord.id,
 97→      },
 98→    },
 99→  );
100→
101→  console.log(`Admin user seeded: ${config.email}`);
102→}
103→
104→async function maybeSeedAdmin(surreal: Surreal): Promise<void> {
105→  const seedConfig = parseSeedConfig(process.env);
106→  if (!seedConfig) return;
107→  await seedAdminUser(surreal, seedConfig);
108→}
109→
110→// --- Migration runner ---
111→
112→const MIGRATIONS_DIR = join(import.meta.dir, "migrations");
113→const migrationGlob = new Bun.Glob("*.surql");
114→
115→const BOOTSTRAP_SQL = `
116→DEFINE TABLE IF NOT EXISTS _migration SCHEMAFULL;
117→DEFINE FIELD IF NOT EXISTS name ON _migration TYPE string;
118→DEFINE FIELD IF NOT EXISTS applied_at ON _migration TYPE datetime;
119→`;
120→
121→function requireEnv(name: string): string {
122→  const value = process.env[name];
123→  if (!value || value.trim().length === 0) {
124→    throw new Error(`${name} is required`);
125→  }
126→  return value.trim();
127→}
128→
129→async function main() {
130→  const url = requireEnv("SURREAL_URL");
131→  const username = requireEnv("SURREAL_USERNAME");
132→  const password = requireEnv("SURREAL_PASSWORD");
133→  const namespace = requireEnv("SURREAL_NAMESPACE");
134→  const database = requireEnv("SURREAL_DATABASE");
135→
136→  const surreal = new Surreal();
137→  await surreal.connect(url);
138→  await surreal.signin({ username, password });
139→  await surreal.use({ namespace, database });
140→
141→  // Bootstrap migration tracking table
142→  await surreal.query(BOOTSTRAP_SQL);
143→
144→  // Read migration files sorted alphabetically
145→  const files = (await Array.fromAsync(migrationGlob.scan(MIGRATIONS_DIR))).sort();
146→
147→  if (files.length === 0) {
148→    console.log("No migration files found.");
149→    await maybeSeedAdmin(surreal);
150→    await surreal.close();
151→    return;
152→  }
153→
154→  // Get already-applied migrations
155→  const [applied] = await surreal.query<[Array<{ name: string }>]>(
156→    "SELECT name FROM _migration;",
157→  );
158→  const appliedSet = new Set(applied.map((row) => row.name));
159→
160→  const pending = files.filter((f) => !appliedSet.has(f));
161→
162→  if (pending.length === 0) {
163→    console.log("No pending migrations.");
164→    await maybeSeedAdmin(surreal);
165→    await surreal.close();
166→    return;
167→  }
168→
169→  console.log(`${pending.length} pending migration(s):\n`);
170→
171→  for (const file of pending) {
172→    const sql = await Bun.file(join(MIGRATIONS_DIR, file)).text();
173→
174→    try {
175→      const stream = surreal.query(sql).stream();
176→      let stmtIndex = 0;
177→      for await (const frame of stream) {
178→        if ((frame as any).status === "ERR") {
179→          console.error(`✗ Failed: ${file} (statement ${stmtIndex})`);
180→          console.error(`  → ${(frame as any).result}`);
181→          await surreal.close();
182→          process.exit(1);
183→        }
184→        stmtIndex++;
185→      }
186→    } catch (err) {
187→      console.error(`✗ Failed: ${file}`);
188→      console.error(err);
189→      await surreal.close();
190→      process.exit(1);
191→    }
192→
193→    const record = new RecordId("_migration", file);
194→    await surreal.query("CREATE $record CONTENT { name: $name, applied_at: time::now() };", {
195→      record,
196→      name: file,
197→    });
198→
199→    console.log(`✓ Applied: ${file}`);
200→  }
201→
202→  console.log(`\nDone. ${pending.length} migration(s) applied.`);
203→  await maybeSeedAdmin(surreal);
204→  await surreal.close();
205→}
206→
207→main().catch((err) => {
208→  console.error("Migration failed:", err);
209→  process.exit(1);
210→});
