 81→        </div>
 82→      </div>
 83→    );
 84→  }
 85→
 86→  return (
 87→    <div className="flex h-screen items-center justify-center bg-background">
 88→      <div className="flex w-full max-w-sm flex-col gap-4 rounded-xl border border-border bg-card p-6">
 89→        <h1 className="text-center text-xl font-bold text-accent">Brain</h1>
 90→        <p className="text-center text-sm text-muted-foreground">
 91→          {effectiveMode === "signin" ? "Sign in to your workspace" : "Create an account"}
 92→        </p>
 93→
 94→        <form onSubmit={handleSubmit} className="flex flex-col gap-3">
 95→          {effectiveMode === "signup" && (
 96→            <Input
 97→              type="text"
 98→              placeholder="Name"
 99→              value={name}
100→              onChange={(e) => setName(e.target.value)}
101→              required
102→            />
103→          )}
104→          <Input
105→            type="email"
106→            placeholder="Email"
107→            value={email}
108→            onChange={(e) => setEmail(e.target.value)}
109→            required
110→          />
111→          <Input
112→            type="password"
113→            placeholder="Password"
114→            value={password}
115→            onChange={(e) => setPassword(e.target.value)}
116→            required
117→            minLength={8}
118→          />
119→
120→          {error && <p className="text-sm text-destructive">{error}</p>}
121→
122→          <Button type="submit" disabled={loading}>
123→            {loading ? "..." : effectiveMode === "signin" ? "Sign in" : "Create account"}
124→          </Button>
125→        </form>
126→
127→        <div className="flex items-center gap-3">
128→          <Separator className="flex-1" />
