 48→export function buildEmailAndPasswordConfig(selfHosted: boolean): EmailAndPasswordConfig {
 49→  if (!selfHosted) {
 50→    return { enabled: true };
 51→  }
 52→
 53→  return {
 54→    enabled: true,
 55→    password: {
 56→      hash: (password: string) => Bun.password.hash(password, "argon2id"),
 57→      verify: ({ hash, password }: { hash: string; password: string }) =>
 58→        Bun.password.verify(password, hash),
 59→    },
 60→  };
